	sql := "SELECT \"scoring_penalties\".* FROM \"scoring_penalties\" WHERE " +
		strmangle.WhereClauseRepeated(string(dialect.LQ), string(dialect.RQ), 1, scoringPenaltyPrimaryKeyColumns, len(*o))

